@@ -0,0 +1,580 @@
+/**
+ * Integration tests for the full analytics pipeline.
+ *
+ * Tests the complete flow: HTTP route handlers → AnalyticsService → Repositories → Database.
+ * Verifies end-to-end correctness with realistic data scenarios.
+ */
+
+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { OrderRepository } from '../../src/repositories/order.repository.js';
+import { AnalyticsService } from '../../src/services/analytics.service.js';
+import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
+import type { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
+import type { AnalyticsQuery, AnalyticsResponse, DashboardData, MetricSummary } from '../../src/models/analytics.js';
+import type { User } from '../../src/models/user.js';
+import type { Order, OrderStatus } from '../../src/models/order.js';
+
+// ---------------------------------------------------------------------------
+// Test data factories
+// ---------------------------------------------------------------------------
+
+let userCounter = 0;
+let orderCounter = 0;
+
+function createUser(repo: UserRepository, overrides: Partial<User> = {}): User {
+  const id = `user-${++userCounter}`;
+  const user: User = {
+    id,
+    name: `User ${userCounter}`,
+    email: `user${userCounter}@example.com`,
+    role: 'member',
+    createdAt: new Date('2025-02-10'),
+    updatedAt: new Date('2025-02-10'),
+    ...overrides,
+  };
+  return repo.save(user);
+}
+
+function createOrder(
+  repo: OrderRepository,
+  userId: string,
+  overrides: Partial<Order> = {},
+): Order {
+  const id = `order-${++orderCounter}`;
+  const order: Order = {
+    id,
+    userId,
+    items: [{ productId: 'prod-1', name: 'Widget', quantity: 1, unitPrice: 50 }],
+    total: 50,
+    status: 'pending',
+    createdAt: new Date('2025-02-15'),
+    updatedAt: new Date('2025-02-15'),
+    ...overrides,
+  };
+  return repo.save(order);
+}
+
+// ---------------------------------------------------------------------------
+// Integration tests
+// ---------------------------------------------------------------------------
+
+describe('Analytics Pipeline Integration', () => {
+  let db: Database;
+  let userRepo: UserRepository;
+  let orderRepo: OrderRepository;
+  let service: AnalyticsService;
+  let routes: AnalyticsRoutes;
+
+  const febQuery: AnalyticsQuery = {
+    startDate: new Date('2025-02-01'),
+    endDate: new Date('2025-02-28T23:59:59.999Z'),
+    granularity: 'day',
+  };
+
+  beforeEach(() => {
+    userCounter = 0;
+    orderCounter = 0;
+    db = new Database();
+    userRepo = new UserRepository(db);
+    orderRepo = new OrderRepository(db);
+    service = new AnalyticsService(orderRepo, userRepo);
+    routes = createAnalyticsRoutes(service);
+  });
+
+  // -------------------------------------------------------------------------
+  // Full dashboard pipeline
+  // -------------------------------------------------------------------------
+
+  describe('full dashboard pipeline', () => {
+    it('should return consistent data across all dashboard sections', async () => {
+      const user1 = createUser(userRepo, { role: 'admin', createdAt: new Date('2025-02-01') });
+      const user2 = createUser(userRepo, { role: 'member', createdAt: new Date('2025-02-05') });
+      const user3 = createUser(userRepo, { role: 'member', createdAt: new Date('2025-01-01') });
+
+      createOrder(orderRepo, user1.id, { total: 100, status: 'delivered', createdAt: new Date('2025-02-03') });
+      createOrder(orderRepo, user1.id, { total: 200, status: 'shipped', createdAt: new Date('2025-02-10') });
+      createOrder(orderRepo, user2.id, { total: 150, status: 'pending', createdAt: new Date('2025-02-15') });
+      createOrder(orderRepo, user2.id, { total: 50, status: 'cancelled', createdAt: new Date('2025-02-20') });
+
+      const result = await routes.getDashboard(febQuery);
+
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      const { data } = result;
+
+      // Metrics should match
+      expect(data.metrics.orders.currentValue).toBe(4);
+      expect(data.metrics.revenue.currentValue).toBe(500);
+      expect(data.metrics.users.currentValue).toBe(2); // only users created in feb
+      expect(data.metrics.averageOrderValue.currentValue).toBe(125);
+
+      // Revenue breakdown should be consistent with metrics
+      expect(data.revenueBreakdown.totalRevenue).toBe(500);
+      expect(data.revenueBreakdown.averageOrderValue).toBe(125);
+
+      // Order status breakdown should sum to total orders
+      const totalFromBreakdown = data.orderStatusBreakdown.reduce((s, b) => s + b.count, 0);
+      expect(totalFromBreakdown).toBe(4);
+
+      // Percentages should sum to 100
+      const percentSum = data.orderStatusBreakdown.reduce((s, b) => s + b.percentage, 0);
+      expect(percentSum).toBe(100);
+
+      // Revenue by status should sum to total
+      const revenueByStatusSum = data.revenueBreakdown.byStatus.reduce((s, b) => s + b.revenue, 0);
+      expect(revenueByStatusSum).toBe(500);
+
+      // User analytics
+      expect(data.userAnalytics.totalUsers).toBe(3);
+      expect(data.userAnalytics.newUsersInPeriod).toBe(2);
+      expect(data.userAnalytics.activeUsersInPeriod).toBe(2);
+
+      // Metadata
+      expect(data.generatedAt).toBeInstanceOf(Date);
+      expect(data.query.granularity).toBe('day');
+    });
+
+    it('should return empty but valid dashboard with no data', async () => {
+      const result = await routes.getDashboard(febQuery);
+
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      const { data } = result;
+      expect(data.metrics.orders.currentValue).toBe(0);
+      expect(data.metrics.revenue.currentValue).toBe(0);
+      expect(data.metrics.users.currentValue).toBe(0);
+      expect(data.metrics.averageOrderValue.currentValue).toBe(0);
+      expect(data.revenueBreakdown.totalRevenue).toBe(0);
+      expect(data.orderStatusBreakdown).toHaveLength(5);
+      expect(data.userAnalytics.totalUsers).toBe(0);
+    });
+
+    it('should include time series data in all metric summaries', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-01') });
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-10') });
+
+      const result = await routes.getDashboard(febQuery);
+
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      for (const key of ['orders', 'revenue', 'users', 'averageOrderValue'] as const) {
+        const metric = result.data.metrics[key];
+        expect(metric.timeSeries.length).toBeGreaterThan(0);
+        for (const point of metric.timeSeries) {
+          expect(point.timestamp).toBeInstanceOf(Date);
+          expect(typeof point.value).toBe('number');
+          expect(point.label).toBeDefined();
+        }
+      }
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Individual metric queries
+  // -------------------------------------------------------------------------
+
+  describe('individual metric queries via routes', () => {
+    it('should return the same values as dashboard for each metric', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-01') });
+      createOrder(orderRepo, user.id, { total: 75, createdAt: new Date('2025-02-05') });
+      createOrder(orderRepo, user.id, { total: 125, createdAt: new Date('2025-02-15') });
+
+      const dashResult = await routes.getDashboard(febQuery);
+      expect(dashResult.success).toBe(true);
+      if (!dashResult.success) return;
+
+      for (const metricType of ['orders', 'revenue', 'users', 'average-order-value'] as const) {
+        const metricResult = await routes.getMetric(metricType, febQuery);
+        expect(metricResult.success).toBe(true);
+        if (!metricResult.success) continue;
+
+        const dashKey = metricType === 'average-order-value' ? 'averageOrderValue' : metricType;
+        const dashMetric = dashResult.data.metrics[dashKey as keyof typeof dashResult.data.metrics];
+
+        expect(metricResult.data.currentValue).toBe(dashMetric.currentValue);
+        expect(metricResult.data.previousValue).toBe(dashMetric.previousValue);
+        expect(metricResult.data.changePercent).toBe(dashMetric.changePercent);
+        expect(metricResult.data.trend).toBe(dashMetric.trend);
+      }
+    });
+
+    it('should return order status breakdown matching dashboard', async () => {
+      const user = createUser(userRepo);
+      createOrder(orderRepo, user.id, { status: 'pending', createdAt: new Date('2025-02-05') });
+      createOrder(orderRepo, user.id, { status: 'delivered', createdAt: new Date('2025-02-10') });
+
+      const dashResult = await routes.getDashboard(febQuery);
+      const statusResult = await routes.getOrderStatus(febQuery);
+
+      expect(dashResult.success).toBe(true);
+      expect(statusResult.success).toBe(true);
+      if (!dashResult.success || !statusResult.success) return;
+
+      expect(statusResult.data).toEqual(dashResult.data.orderStatusBreakdown);
+    });
+
+    it('should return revenue breakdown matching dashboard', async () => {
+      const user = createUser(userRepo);
+      createOrder(orderRepo, user.id, { total: 200, status: 'shipped', createdAt: new Date('2025-02-05') });
+
+      const dashResult = await routes.getDashboard(febQuery);
+      const revenueResult = await routes.getRevenue(febQuery);
+
+      expect(dashResult.success).toBe(true);
+      expect(revenueResult.success).toBe(true);
+      if (!dashResult.success || !revenueResult.success) return;
+
+      expect(revenueResult.data.totalRevenue).toBe(dashResult.data.revenueBreakdown.totalRevenue);
+      expect(revenueResult.data.averageOrderValue).toBe(dashResult.data.revenueBreakdown.averageOrderValue);
+    });
+
+    it('should return user analytics matching dashboard', async () => {
+      createUser(userRepo, { role: 'admin', createdAt: new Date('2025-02-01') });
+      createUser(userRepo, { role: 'member', createdAt: new Date('2025-02-10') });
+
+      const dashResult = await routes.getDashboard(febQuery);
+      const userResult = await routes.getUserAnalytics(febQuery);
+
+      expect(dashResult.success).toBe(true);
+      expect(userResult.success).toBe(true);
+      if (!dashResult.success || !userResult.success) return;
+
+      expect(userResult.data.totalUsers).toBe(dashResult.data.userAnalytics.totalUsers);
+      expect(userResult.data.newUsersInPeriod).toBe(dashResult.data.userAnalytics.newUsersInPeriod);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Time-range filtering
+  // -------------------------------------------------------------------------
+
+  describe('time-range filtering', () => {
+    it('should only include data within the specified range', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-01-01') });
+
+      // Orders in January
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-01-15') });
+      createOrder(orderRepo, user.id, { total: 200, createdAt: new Date('2025-01-20') });
+
+      // Orders in February
+      createOrder(orderRepo, user.id, { total: 300, createdAt: new Date('2025-02-10') });
+
+      // Orders in March
+      createOrder(orderRepo, user.id, { total: 400, createdAt: new Date('2025-03-05') });
+
+      const result = await routes.getDashboard(febQuery);
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      expect(result.data.metrics.orders.currentValue).toBe(1);
+      expect(result.data.metrics.revenue.currentValue).toBe(300);
+    });
+
+    it('should compute period-over-period comparison correctly', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-01-01') });
+
+      // Jan orders (previous period for Feb query)
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-01-05') });
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-01-15') });
+
+      // Feb orders (current period)
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-05') });
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-10') });
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-20') });
+
+      const result = await routes.getMetric('orders', febQuery);
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      expect(result.data.currentValue).toBe(3);
+      expect(result.data.previousValue).toBe(2);
+      expect(result.data.changePercent).toBe(50);
+      expect(result.data.trend).toBe('up');
+    });
+
+    it('should handle narrow time ranges', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-15') });
+      createOrder(orderRepo, user.id, { total: 50, createdAt: new Date('2025-02-15T10:00:00Z') });
+      createOrder(orderRepo, user.id, { total: 75, createdAt: new Date('2025-02-15T14:00:00Z') });
+
+      const narrowQuery: AnalyticsQuery = {
+        startDate: new Date('2025-02-15T00:00:00Z'),
+        endDate: new Date('2025-02-15T23:59:59.999Z'),
+        granularity: 'hour',
+      };
+
+      const result = await routes.getDashboard(narrowQuery);
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      expect(result.data.metrics.orders.currentValue).toBe(2);
+      expect(result.data.metrics.revenue.currentValue).toBe(125);
+      expect(result.data.metrics.orders.timeSeries.length).toBeGreaterThanOrEqual(24);
+    });
+
+    it('should handle different granularities consistently', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-01') });
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-10') });
+
+      for (const granularity of ['hour', 'day', 'week', 'month'] as const) {
+        const query: AnalyticsQuery = { ...febQuery, granularity };
+        const result = await routes.getDashboard(query);
+        expect(result.success).toBe(true);
+        if (!result.success) continue;
+
+        // Core values should be the same regardless of granularity
+        expect(result.data.metrics.orders.currentValue).toBe(1);
+        expect(result.data.metrics.revenue.currentValue).toBe(100);
+
+        // Time series should have appropriate bucket count
+        const seriesLength = result.data.metrics.orders.timeSeries.length;
+        if (granularity === 'hour') expect(seriesLength).toBeGreaterThan(24);
+        if (granularity === 'day') expect(seriesLength).toBeGreaterThanOrEqual(28);
+        if (granularity === 'month') expect(seriesLength).toBeLessThanOrEqual(2);
+      }
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Error scenarios
+  // -------------------------------------------------------------------------
+
+  describe('error scenarios', () => {
+    it('should return error for invalid date parameters', async () => {
+      const result = await routes.getDashboard({
+        startDate: new Date('not-a-date'),
+        endDate: new Date('2025-02-28'),
+      });
+
+      expect(result.success).toBe(false);
+      if (!result.success) {
+        expect(result.error).toContain('Invalid startDate');
+        expect(result.meta.generatedAt).toBeInstanceOf(Date);
+        expect(result.meta.queryDurationMs).toBeGreaterThanOrEqual(0);
+      }
+    });
+
+    it('should return error when start date is after end date', async () => {
+      const result = await routes.getDashboard({
+        startDate: new Date('2025-03-01'),
+        endDate: new Date('2025-02-01'),
+      });
+
+      expect(result.success).toBe(false);
+      if (!result.success) {
+        expect(result.error).toContain('startDate must be before endDate');
+      }
+    });
+
+    it('should return error for invalid metric type', async () => {
+      const result = await routes.getMetric('nonexistent', febQuery);
+
+      expect(result.success).toBe(false);
+      if (!result.success) {
+        expect(result.error).toContain('Invalid metric type');
+        expect(result.error).toContain('nonexistent');
+      }
+    });
+
+    it('should return error for invalid granularity', async () => {
+      const result = await routes.getDashboard({
+        startDate: new Date('2025-02-01'),
+        endDate: new Date('2025-02-28'),
+        granularity: 'quarter' as any,
+      });
+
+      expect(result.success).toBe(false);
+      if (!result.success) {
+        expect(result.error).toContain('Invalid granularity');
+      }
+    });
+
+    it('should validate parameters on all route endpoints', async () => {
+      const invalidQuery: AnalyticsQuery = {
+        startDate: new Date('2025-03-01'),
+        endDate: new Date('2025-02-01'),
+      };
+
+      const results = await Promise.all([
+        routes.getDashboard(invalidQuery),
+        routes.getMetric('orders', invalidQuery),
+        routes.getOrderStatus(invalidQuery),
+        routes.getRevenue(invalidQuery),
+        routes.getUserAnalytics(invalidQuery),
+      ]);
+
+      for (const result of results) {
+        expect(result.success).toBe(false);
+      }
+    });
+
+    it('should not include data property in error responses', async () => {
+      const result = await routes.getDashboard({
+        startDate: new Date('invalid'),
+        endDate: new Date('2025-02-28'),
+      });
+
+      expect(result.success).toBe(false);
+      expect('data' in result).toBe(false);
+      expect('error' in result).toBe(true);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Realistic multi-user scenario
+  // -------------------------------------------------------------------------
+
+  describe('realistic multi-user scenario', () => {
+    it('should handle a realistic e-commerce dataset', async () => {
+      // Create users with different roles across time
+      const admin = createUser(userRepo, { role: 'admin', createdAt: new Date('2025-01-01') });
+      const member1 = createUser(userRepo, { role: 'member', createdAt: new Date('2025-02-01') });
+      const member2 = createUser(userRepo, { role: 'member', createdAt: new Date('2025-02-10') });
+      const viewer = createUser(userRepo, { role: 'viewer', createdAt: new Date('2025-02-15') });
+
+      // Varied orders across statuses and dates
+      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
+      const orders: Order[] = [];
+      for (let i = 0; i < 20; i++) {
+        const day = ((i % 27) + 1).toString().padStart(2, '0');
+        const userId = [admin.id, member1.id, member2.id][i % 3];
+        const order = createOrder(orderRepo, userId, {
+          total: 25 + i * 10,
+          status: statuses[i % 5],
+          createdAt: new Date(`2025-02-${day}T${(8 + i % 12).toString().padStart(2, '0')}:00:00Z`),
+        });
+        orders.push(order);
+      }
+
+      const result = await routes.getDashboard(febQuery);
+      expect(result.success).toBe(true);
+      if (!result.success) return;
+
+      const { data } = result;
+
+      // Verify order count
+      expect(data.metrics.orders.currentValue).toBe(20);
+
+      // Verify revenue matches sum of order totals
+      const expectedRevenue = orders.reduce((sum, o) => sum + o.total, 0);
+      expect(data.metrics.revenue.currentValue).toBe(expectedRevenue);
+
+      // Verify average order value
+      expect(data.metrics.averageOrderValue.currentValue).toBe(
+        Math.round((expectedRevenue / 20) * 100) / 100,
+      );
+
+      // Verify user analytics
+      expect(data.userAnalytics.totalUsers).toBe(4);
+      expect(data.userAnalytics.newUsersInPeriod).toBe(3); // member1, member2, viewer
+      expect(data.userAnalytics.activeUsersInPeriod).toBe(3); // admin, member1, member2
+
+      // Verify role breakdown
+      const adminRole = data.userAnalytics.byRole.find((r) => r.role === 'admin');
+      expect(adminRole?.count).toBe(1);
+      const memberRole = data.userAnalytics.byRole.find((r) => r.role === 'member');
+      expect(memberRole?.count).toBe(2);
+      const viewerRole = data.userAnalytics.byRole.find((r) => r.role === 'viewer');
+      expect(viewerRole?.count).toBe(1);
+
+      // Status breakdown should have 4 of each status (20 orders / 5 statuses)
+      for (const status of statuses) {
+        const entry = data.orderStatusBreakdown.find((b) => b.status === status)!;
+        expect(entry.count).toBe(4);
+        expect(entry.percentage).toBe(20);
+      }
+
+      // Time series should have non-zero entries
+      const nonZeroBuckets = data.metrics.orders.timeSeries.filter((p) => p.value > 0);
+      expect(nonZeroBuckets.length).toBeGreaterThan(0);
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Data layer consistency
+  // -------------------------------------------------------------------------
+
+  describe('data layer consistency', () => {
+    it('should reflect newly added data immediately', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-01') });
+
+      // First query - no orders
+      const result1 = await routes.getDashboard(febQuery);
+      expect(result1.success).toBe(true);
+      if (result1.success) {
+        expect(result1.data.metrics.orders.currentValue).toBe(0);
+      }
+
+      // Add an order
+      createOrder(orderRepo, user.id, { total: 100, createdAt: new Date('2025-02-15') });
+
+      // Second query - should see the new order
+      const result2 = await routes.getDashboard(febQuery);
+      expect(result2.success).toBe(true);
+      if (result2.success) {
+        expect(result2.data.metrics.orders.currentValue).toBe(1);
+        expect(result2.data.metrics.revenue.currentValue).toBe(100);
+      }
+    });
+
+    it('should produce consistent results across concurrent route calls', async () => {
+      const user = createUser(userRepo, { createdAt: new Date('2025-02-01') });
+      createOrder(orderRepo, user.id, { total: 100, status: 'delivered', createdAt: new Date('2025-02-05') });
+      createOrder(orderRepo, user.id, { total: 200, status: 'pending', createdAt: new Date('2025-02-10') });
+
+      const [dashboard, metric, status, revenue, userAnalytics] = await Promise.all([
+        routes.getDashboard(febQuery),
+        routes.getMetric('orders', febQuery),
+        routes.getOrderStatus(febQuery),
+        routes.getRevenue(febQuery),
+        routes.getUserAnalytics(febQuery),
+      ]);
+
+      expect(dashboard.success).toBe(true);
+      expect(metric.success).toBe(true);
+      expect(status.success).toBe(true);
+      expect(revenue.success).toBe(true);
+      expect(userAnalytics.success).toBe(true);
+
+      if (dashboard.success && metric.success) {
+        expect(metric.data.currentValue).toBe(dashboard.data.metrics.orders.currentValue);
+      }
+      if (dashboard.success && revenue.success) {
+        expect(revenue.data.totalRevenue).toBe(dashboard.data.revenueBreakdown.totalRevenue);
+      }
+    });
+  });
+
+  // -------------------------------------------------------------------------
+  // Response envelope structure
+  // -------------------------------------------------------------------------
+
+  describe('response envelope structure', () => {
+    it('should wrap successful responses with meta information', async () => {
+      const result = await routes.getDashboard(febQuery);
+
+      expect(result.success).toBe(true);
+      expect(result.meta).toBeDefined();
+      expect(result.meta.generatedAt).toBeInstanceOf(Date);
+      expect(typeof result.meta.queryDurationMs).toBe('number');
+      expect(result.meta.queryDurationMs).toBeGreaterThanOrEqual(0);
+    });
+
+    it('should wrap error responses with meta information', async () => {
+      const result = await routes.getDashboard({
+        startDate: new Date('invalid'),
+        endDate: new Date('2025-02-28'),
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.meta).toBeDefined();
+      expect(result.meta.generatedAt).toBeInstanceOf(Date);
+      expect(typeof result.meta.queryDurationMs).toBe('number');
+    });
+  });
+});

